/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // The problem condition "every cycle's edge weight sum is even" is equivalent
    // to saying that the graph must be bipartite when considering edge weights modulo 2.
    // Since weights are 0 or 1, we are concerned with parity.
    // If we consider a graph where edge weight w_i is 1 if w_i=1 and 0 if w_i=0,
    // the condition means that for any cycle, the sum of weights (modulo 2) must be 0.
    // This is the fundamental property of a bipartite graph coloring, but applied to parities.

    // We can use a Disjoint Set Union (DSU) structure modified to track relative parity.
    // For each node i, we will maintain:
    // 1. parent[i]: The parent of node i in the DSU tree.
    // 2. parity[i]: The parity of the path distance (sum of weights modulo 2)
    //    from node i to its current parent (parent[i]).

    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the parity of the path sum from i to parent[i].
    // 0 means even path sum, 1 means odd path sum.
    const parity = Array(n).fill(0);

    /**
     * Finds the representative (root) of the set containing i,
     * and updates the parity[i] to be the parity of the path from i to the root.
     * @param {number} i
     * @returns {number} The root of the set.
     */
    function find(i) {
        if (parent[i] === i) {
            return i;
        }
        const root = find(parent[i]);
        // Path compression: Update parity[i] to be the parity of the path from i to root.
        // Path(i -> root) = Path(i -> parent[i]) + Path(parent[i] -> root) (mod 2)
        parity[i] = (parity[i] + parity[parent[i]]) % 2;
        parent[i] = root;
        return root;
    }

    /**
     * Tries to unite the sets containing u and v using the edge (u, v) with weight w.
     * @param {number} u
     * @param {number} v
     * @param {number} w Edge weight (0 or 1).
     * @returns {boolean} True if the edge was added (no conflict), False otherwise.
     */
    function union(u, v, w) {
        const rootU = find(u);
        const rootV = find(v);

        if (rootU !== rootV) {
            // Different components: We can always add the edge.
            // Merge V's component into U's component (arbitrarily).
            parent[rootV] = rootU;

            // We need to determine parity[rootV], which is the parity of the path
            // from rootV to rootU.
            // We know:
            // 1. Path(u -> rootU) has parity parity[u]
            // 2. Path(v -> rootV) has parity parity[v]
            // 3. The new edge (u, v) has parity w.
            // 4. We want Path(rootV -> rootU).

            // Path(rootV -> u) + Path(u -> v) + Path(v -> rootV) = 0 (since u and v are connected)
            // Path(rootV -> u) = Path(rootV -> rootV) + Path(rootV -> rootU) + Path(rootU -> u) (this is complicated)

            // A simpler way: We are setting parent[rootV] = rootU.
            // We need parity[rootV] = parity(rootV -> rootU).
            // Path(rootV -> rootU) = Path(rootV -> v) + Path(v -> u) + Path(u -> rootU)
            // Parity(rootV -> v) = Parity(v -> rootV) = parity[v] (since path is undirected)
            // Parity(v -> u) = w
            // Parity(u -> rootU) = parity[u]
            // Therefore:
            // parity[rootV] = (parity[v] + w + parity[u]) % 2

            parity[rootV] = (parity[u] + w + parity[v]) % 2;
            return true;
        } else {
            // Same component: Check for cycle consistency.
            // The path between u and v in the existing graph has parity:
            // Path(u -> rootU) + Path(v -> rootU) (since rootU=rootV)
            // Existing cycle parity = Path(u -> v) = parity[u] + parity[v] (mod 2)

            // The new edge (u, v) has weight w.
            // The total cycle weight parity is: (Existing path parity) + w
            // Cycle parity = (parity[u] + parity[v] + w) % 2

            // We require this to be 0 (even).
            if ((parity[u] + parity[v] + w) % 2 === 0) {
                // Condition met, add the edge (it doesn't change connectivity structure,
                // but it is accepted by the rule).
                return true;
            } else {
                // Condition violated (cycle sum is odd). Reject the edge.
                return false;
            }
        }
    }

    let addedEdgesCount = 0;

    for (const [u, v, w] of edges) {
        if (union(u, v, w)) {
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}

